protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Breaking change: HasIndex now throws on Cosmos (was silently ignored) — removed.

    // Breaking change: discriminator JSON property renamed from "Discriminator" to "$type".
    // Keep old name so existing documents are still found.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Breaking change: JSON id no longer includes discriminator ("Blog|1" → "1").
    // Keep old format so existing documents with "Blog|1" ids are still found.
    modelBuilder.Entity<Blog>().HasDiscriminatorInJsonId();

    // Breaking change: key property is now mapped directly to JSON "id".
    // Keep the old shadow-property behaviour so the "Id" JSON field is preserved.
    modelBuilder.Entity<Blog>().HasShadowId();
}

